protected void endLedgerVoucher()
{

    PurchParmLine               purchParmLineloc = purchParmLine;
    PurchLine                   purchLineloc = purchLine;
    PurchTable                  purchTableloc = purchTable;
    PurchFormLetter purchFormLetter;
    VendPackingSlipJour         vendPackingSlipJourloc = vendPackingSlipJour;
    VendPackingSlipTrans        vendPackingSlipTransloc = vendPackingSlipTrans;
    PurchLine                   purchline = purchParmLineloc.purchline();
    next endLedgerVoucher();

    VendPackingSlipJour::inserMarkupTrans(purchParmLineloc);

    ttsbegin;
    purchFormLetter = PurchFormLetter::construct(DocumentStatus::PurchaseOrder);
    purchFormLetter.update(purchTableloc,'');
    ttscommit;
}

//NS--04-04-2025 --BL insert the records in ETGBlNumber table.
protected void endPost()
{
    next endPost();

    if (ETGACFParameters::find().BLNumberAutomation)
    {
        PurchParmLine purchParmLineloc = purchParmLine;
        EcoResProduct ecoResProduct    = EcoResProduct::find(InventTable::find(purchParmLineloc.ItemId).Product);

        if(ecoResProduct.ProductType == EcoResProductType::Item)
        {
            this.createBlnumber();
        }
    }
}

/// <summary>
/// insert the records in ETGBlNumber table.
/// </summary>
private void createBlnumber()
{

    VendPackingSlipTrans vendPackingSlipTrans;
    ETGBlNumber          eTGBlNumber;
    InventDim            inventDim;
    InventTrans          inventTrans;
    VendPackingSlipJour  vendPackingSlipJourloc = vendPackingSlipJour;


    while select ItemId,Qty,PackingSlipId,OrigPurchid,InventDimId, LineNum from vendPackingSlipTrans
          where  vendPackingSlipTrans.VendPackingSlipJour == vendPackingSlipJour.RecId
    {

        inventDim                           =  InventDim::find(vendPackingSlipTrans.InventDimId);
        eTGBlNumber.clear();
        eTGBlNumber.ItemNumber              = vendPackingSlipTrans.ItemId;
        eTGBlNumber.Qty                     = vendPackingSlipTrans.Qty;
        eTGBlNumber.ProductReceiptNumber    = vendPackingSlipJourloc.PackingSlipId;
        eTGBlNumber.BatchNumber             = inventDim.inventBatchId;
        eTGBlNumber.SerialNumber            = inventDim.inventSerialId;
        eTGBlNumber.PurchId                 = vendPackingSlipTrans.OrigPurchid;
        eTGBlNumber.insert();


    }

}


